using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries reference
            // c.Discriminator — preserve the old property name.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change: id property no longer includes the discriminator prefix.
            // Existing documents use "Product|123" format — preserve it.
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id".
            // Existing documents store Id separately (e.g. "Id": 123) alongside the
            // shadow "id" ("Product|123") — preserve the shadow property.
            b.HasShadowId();

            // Breaking change: HasIndex now throws on Cosmos (indexes are managed via
            // Azure Portal). Removed the previous HasIndex(p => p.Sku) call.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

