using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // Breaking change: sync I/O now throws InvalidOperationException.
    // All Cosmos DB queries must use async APIs.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Breaking change: EF9 SQL projections now require the VALUE keyword.
        // "SELECT *" must become "SELECT VALUE c" when executed via FromSqlRaw.
        // c.Discriminator still works because we preserved the old property name.
        var sql = "SELECT VALUE c FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Breaking change: ToList() throws; must use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

